UPDATE leads SET bonus_song_url = NULL, bonus_preview_url = NULL, bonus_automation_status = NULL, bonus_automation_task_id = NULL, bonus_automation_started_at = NULL, bonus_automation_last_error = NULL, bonus_song_title = NULL, bonus_style_prompt = NULL, bonus_cover_image_url = NULL WHERE genre = 'acoustic' AND bonus_song_title LIKE '%(Acoustic)%' AND bonus_automation_status = 'completed';